    // Construct an object to manage view state
    glfw_state app_state;
    // register callbacks to allow manipulation of the pointcloud
    register_glfw_callbacks(app, app_state);
    
     

    // Declare pointcloud object, for calculating pointclouds and texture mappings
    rs2::pointcloud pc;
    // We want the points object to be persistent so we can display the last cloud when a frame drops
    rs2::points points;

    // Declare RealSense pipeline, encapsulating the actual device and sensors
    //rs2::pipeline pipe = std::make_shared<rs::pipeline>();
    auto pipe = std::make_shared<rs2::pipeline>();

    rs2::config cfg;
    //cfg.enable_device_from_file("a.bag");
    string str0 = "a.bag";
    string str1 = "a.bag";
    //cfg.enable_device_from_file(str0.c_str());  
    cfg.enable_record_to_file(str1.c_str());
    pipe->start(cfg); //File will be opened at this point 

    // Start streaming with default recommended configuration
    //pipe->start();
    rs2::device device = pipe->get_active_profile().get_device();

    string filename;
    int n = 0;

    struct timeval start;
    int frame_cnt = 0;
    string filelogname = "stream.log";
    FILE* pfFilelog = fopen(filelogname.c_str(),"w");
    cout << "loop starts" << endl; 
    while (app) // Application still alive?
    {
        //filename = "/var/voters/bulk_c/MA_Office/206/realsensedata/pcd"+to_string(n);
	filename = to_string(n)+".ply";        
	// Wait for the next set of frames from the camera
	cout << "get the time now"<< endl;	
	gettimeofday(&start, NULL);        
	cout << "time obtained : " << start.tv_sec << " sec, " << start.tv_usec << " usec" <<endl;
	auto frames = pipe->wait_for_frames();

        auto depth = frames.get_depth_frame();

        // Generate the pointcloud and texture mappings
        points = pc.calculate(depth);

        auto color = frames.get_color_frame();

        // Tell pointcloud object to map to this color frame
        pc.map_to(color);
	
	points.export_to_ply(filename, color);
	cout << "point cloud file saved." << endl;
        fprintf(pfFilelog,"%d,%d,%d\n",start.tv_sec,start.tv_usec,frame_cnt);
	fflush(pfFilelog);
	cout << "write to log at frame: " << frame_cnt << endl; 
	frame_cnt++;

        // Upload the color frame to OpenGL
        app_state.tex.upload(color);

        // Draw the pointcloud
        draw_pointcloud(app.width(), app.height(), app_state, points);
 	n++;
    }

    fclose(pfFilelog);
    return EXIT_SUCCESS;
}
catch (const rs2::error & e)
{
    std::cerr << "RealSense error calling " << e.get_failed_function() << "(" << e.get_failed_args() << "):\n    " << e.what() << std::endl;
    return EXIT_FAILURE;
}
catch (const std::exception & e)
{
    std::cerr << e.what() << std::endl;
    return EXIT_FAILURE;
}

